import osimport sysimport timeimport threadingimport itertoolsfrom dotenv import load_dotenvfrom langchain_classic.memory import ConversationBufferMemoryfrom langchain_groq import ChatGroqfrom langchain_core.prompts import ChatPromptTemplate, MessagesPlaceholderfrom langchain_core.messages import HumanMessage, AIMessage, SystemMessageload_dotenv()GROQ_API_KEY   = os.getenv("groq_api_key")MODEL_NAME     = "llama-3.1-8b-instant"TEMPERATURE    = 0.7MAX_TOKENS     = 1024MAX_HISTORY    = 10SYSTEM_PROMPT  = """You are a cancer specialized, friendly, and knowledgeable AI assistant.Answer the user's questions clearly and concisely and with that whatever they asked about cancer give the response in three parts knowledge about the disease second part is treatment and third part is best treatment availabilities .If you don't know something, say so honestly."""class Spinner:    FRAMES = ["⣾","⣽","⣻","⢿","⡿","⣟","⣯","⣷"]    def __init__(self, msg="Thinking"):        self.msg    = msg        self._stop  = threading.Event()        self._t     = None    def _run(self):        for f in itertools.cycle(self.FRAMES):            if self._stop.is_set():                break            sys.stdout.write(f"\r\033[36m{f} {self.msg}...\033[0m]   ")            sys.stdout.flush()            time.sleep(0.08)        sys.stdout.write("\r" + " " * 30 + "\r")        sys.stdout.flush()    def start(self):        self._stop.clear()        self._t = threading.Thread(target=self._run, daemon=True)        self._t.start()    def stop(self):        self._stop.set()        if self._t:            self._t.join()class GroqChatbot:    def __init__(self):        self.api_key = os.getenv("groq_api_key")        if not self.api_key:            raise ValueError(                "Set your GROQ_API_KEY in .env or directly in CONFIG above.\n"                "Get a free key at https://console.groq.com"            )        # LLM — streaming ON        self.llm = ChatGroq(            api_key=GROQ_API_KEY,            model_name="llama-3.1-8b-instant",            temperature=TEMPERATURE,            max_tokens=MAX_TOKENS,            streaming=True,        )        self.memory = ConversationBufferMemory(            return_messages=True,            memory_key="history"        )        self.prompt = ChatPromptTemplate.from_messages([            SystemMessage(content=SYSTEM_PROMPT),            MessagesPlaceholder(variable_name="history"),            ("human", "{question}"),        ])        self.chain = self.prompt | self.llm    def ask(self, question: str) -> str:        """        Send a question, stream the response token by token.        Saves both question and answer into memory automatically.        Returns the full response string.        """        # Load history from memory        history = self.memory.load_memory_variables({})["history"]        spinner = Spinner("Thinking")        spinner.start()        full_response = []        try:            stream = self.chain.stream({                "history":  history,                "question": question,            })            # Stop spinner just before first token arrives            first = True            for chunk in stream:                if first:                    spinner.stop()                    # Print answer header                    print("\033[32m\033[1m" + "─" * 55 + "\033[0m")                    print("\033[35m\033[1m🤖 Assistant:\033[0m")                    first = False                token = chunk.content                print(token, end="", flush=True)                full_response.append(token)        except Exception as e:            spinner.stop()            print(f"\033[31m\nError: {e}\033[0m")            return ""        print("\n\033[32m\033[1m" + "─" * 55 + "\033[0m\n")        answer = "".join(full_response)        self.memory.save_context(            {"input":  question},            {"output": answer},        )        return answer    def clear_memory(self):        """Wipe conversation history."""        self.memory.clear()        print("\033[33mMemory cleared.\033[0m\n")    def show_history(self):        """Print the current conversation history."""        msgs = self.memory.load_memory_variables({})["history"]        if not msgs:            print("\033[33mNo history yet.\033[0m\n")            return        print("\n\033[33m\033[1m── Conversation History ──\033[0m")        for m in msgs:            role  = "You" if isinstance(m, HumanMessage) else "Bot"            color = "\033[34m" if role == "You" else "\033[35m"            print(f"{color}{role}:\033[0m {m.content[:120]}{'…' if len(m.content)>120 else ''}")        print()def chat_loop():    print("\033[36m\033[1m")    print("╔══════════════════════════════════════════════════════╗")    print("║        🤖  CANCER INTELLIGENCE RAG MODEL            ║")    print(f"║        Model : {MODEL_NAME:<37}║")    print("╚══════════════════════════════════════════════════════╝")    print("\033[0m")    print("\033[2mCommands:  /clear — reset memory  |  /history — show history  |  /quit — exit\033[0m\n")    bot = GroqChatbot()    while True:        try:            user_input = input("\033[34m\033[1mYou › \033[0m").strip()        except (KeyboardInterrupt, EOFError):            print("\n\033[36mGoodbye! 👋\033[0m\n")            break        if not user_input:            continue        if user_input.lower() in ("/quit", "/exit"):            print("\033[36mGoodbye! 👋\033[0m\n")            break        elif user_input.lower() == "/clear":            bot.clear_memory()        elif user_input.lower() == "/history":            bot.show_history()        else:            bot.ask(user_input)if __name__ == "__main__":    chat_loop()